package main

import (
	"fmt"
	"io/ioutil"
	"os"
	"strings"
)

func main() {
	args := os.Args[1:]
	if len(args) < 5 {
		panic("Provide 5 arguments [inputFile package (var|const) varName outputFile]")
	}

	inputFile := args[0]
	pkg := args[1]
	declaration := args[2]
	varName := args[3]
	outputFile := args[4]

	body, bodyErr := ioutil.ReadFile(inputFile)
	handleErr(bodyErr)

	output := `// +build !stubfile

// Code generated by embed-file; DO NOT EDIT.

package {{pkg}}

{{declaration}} {{var}} = {{val}}
`

	output = strings.Replace(output, "{{pkg}}", pkg, 1)
	output = strings.Replace(output, "{{declaration}}", declaration, 1)
	output = strings.Replace(output, "{{var}}", varName, 1)
	output = strings.Replace(output, "{{val}}", fmt.Sprintf("%+q", string(body)), 1)

	writeErr := ioutil.WriteFile(outputFile, []byte(output), 0644)
	handleErr(writeErr)
}

func handleErr(err error) {
	if err != nil {
		panic(err)
	}
}
